import 'package:baseball_detector_flutter/data/models/plan.dart';
import 'package:baseball_detector_flutter/data/models/team_plan.dart';

void main() {
  const id = '77777777-0003-0001-0000-000000000001';
  const teamId = '00000000-0000-4000-8000-000000000000';
  const planId = '2';
  final startDate = DateTime.now().subtract(const Duration(days: 1));
  final endDate = DateTime.now().add(const Duration(days: 90));
  const isPendingActivation = false;
  const currentUsage = 90;
  const isActive = true;
  const extraBalls = 0;
  final createdAt = DateTime.now().subtract(const Duration(days: 1));
  final updatedAt = DateTime.now().subtract(const Duration(days: 1));
  final plan = Plan(
    id: '2',
    name: 'Test plan',
    description: 'Test description',
    type: 1,
    maxBalls: 1000,
    createdAt: createdAt,
    updatedAt: updatedAt,
  );
  final defaultTeamPlan = TeamPlan(
    id: id,
    teamId: teamId,
    planId: planId,
    startDate: startDate,
    endDate: endDate,
    currentUsage: currentUsage,
    isActive: isActive,
    isPendingActivation: isPendingActivation,
    extraBalls: extraBalls,
    createdAt: createdAt,
    updatedAt: updatedAt,
    plan: plan,
  );
  group('Testing TeamPlan', () {
    test('toJson1', () {
      final teamPlanJson = defaultTeamPlan.toJson();

      expect(teamPlanJson.length, 14);

      expect(teamPlanJson.containsKey('id'), isTrue);
      expect(teamPlanJson.containsKey('teamId'), isTrue);
      expect(teamPlanJson.containsKey('planId'), isTrue);
      expect(teamPlanJson.containsKey('startDate'), isTrue);
      expect(teamPlanJson.containsKey('endDate'), isTrue);
      expect(teamPlanJson.containsKey('currentUsage'), isTrue);
      expect(teamPlanJson.containsKey('isActive'), isTrue);
      expect(teamPlanJson.containsKey('isPendingActivation'), isTrue);
      expect(teamPlanJson.containsKey('extraBalls'), isTrue);
      expect(teamPlanJson.containsKey('createdAt'), isTrue);
      expect(teamPlanJson.containsKey('updatedAt'), isTrue);
      expect(teamPlanJson.containsKey('plan'), isTrue);

      expect(teamPlanJson['id'], id);
      expect(teamPlanJson['teamId'], teamId);
      expect(teamPlanJson['planId'], planId);
      expect(teamPlanJson['startDate'], startDate.toIso8601String());
      expect(teamPlanJson['endDate'], endDate.toIso8601String());
      expect(teamPlanJson['currentUsage'], currentUsage);
      expect(teamPlanJson['isActive'], isActive);
      expect(teamPlanJson['isPendingActivation'], isPendingActivation);
      expect(teamPlanJson['extraBalls'], extraBalls);
      expect(teamPlanJson['createdAt'], createdAt.toIso8601String());
      expect(teamPlanJson['updatedAt'], updatedAt.toIso8601String());
      expect(teamPlanJson['plan'], plan.toJson());

      final deserializedTeamPlan = TeamPlan.fromJson(teamPlanJson);
      expect(deserializedTeamPlan, defaultTeamPlan);
    });

    test('fromJson1 (API New)', () {
      final teamJson = {
        'id': id,
        'teamId': teamId,
        'planId': planId,
        'startDate': startDate.toIso8601String(),
        'endDate': endDate.toIso8601String(),
        'currentUsage': currentUsage,
        'isActive': isActive,
        'isPendingActivation': isPendingActivation,
        'extraBalls': extraBalls,
        'createdAt': createdAt.toIso8601String(),
