        'plan': {
          'id': plan.id,
          'name': plan.name,
          'description': plan.description,
          'type': plan.type.toString(),
          'maxBalls': plan.maxBalls.toString(),
          'createdAt': plan.createdAt!.toIso8601String(),
          'updatedAt': plan.updatedAt!.toIso8601String(),
        },

      };

      final teamPlan = TeamPlan.fromJson(teamJson);

      expect(teamPlan.id, id);
      expect(teamPlan.teamId, teamId);
      expect(teamPlan.planId, planId);
      expect(teamPlan.startDate, startDate);
      expect(teamPlan.endDate, endDate);
      expect(teamPlan.currentUsage, currentUsage);
      expect(teamPlan.isActive, isActive);
      expect(teamPlan.isPendingActivation, isPendingActivation);
      expect(teamPlan.extraBalls, extraBalls);
      expect(teamPlan.createdAt, createdAt);
      expect(teamPlan.updatedAt, updatedAt);
      expect(teamPlan.plan, plan);

      final serializedJson = teamPlan.toJson();
      expect(serializedJson, teamJson);
    });

    test('fromJson1 (API Old)', () {
      const oldId = 1;
      final teamJson = {
        'id': oldId,
        'teamId': teamId,
        'planId': planId,
        'startDate': startDate.toIso8601String(),
        'endDate': endDate.toIso8601String(),
        'currentUsage': currentUsage,
        'isActive': isActive,
        'isPendingActivation': isPendingActivation,
        'extraBalls': extraBalls,
        'createdAt': createdAt.toIso8601String(),
        'updatedAt': updatedAt.toIso8601String(),
        'plan': {
          'id': plan.id,
          'name': plan.name,
          'description': plan.description,
          'type': plan.type.toString(),
          'maxBalls': plan.maxBalls.toString(),
          'createdAt': plan.createdAt!.toIso8601String(),
          'updatedAt': plan.updatedAt!.toIso8601String(),
        },
      };

      final teamPlan = TeamPlan.fromJson(teamJson);

      expect(teamPlan.id, oldId.toString());
      expect(teamPlan.teamId, teamId);
      expect(teamPlan.planId, planId);
      expect(teamPlan.startDate, startDate);
      expect(teamPlan.endDate, endDate);
      expect(teamPlan.currentUsage, currentUsage);
      expect(teamPlan.isActive, isActive);
      expect(teamPlan.isPendingActivation, isPendingActivation);
