import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/short_role_info.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';

class FakeUserAccessibleContentsController
    extends UserAccessibleContentsController {
  @override
  UserAccessibleContents? build() {
    // For testing, return admin permissions for both common test teams
    return _adminAllDomainsForTeams();
  }

  @override
  Future<UserAccessibleContents?> refresh() async {
    state = _adminAllDomainsForTeams();
    return state;
  }
}

UserAccessibleContents _adminAllDomainsForTeams() {
  makeDomain() => {
        RoleLevel.read:
            const ShortRoleInfo(isAccessible: true, isTeamCrossing: true),
        RoleLevel.write:
            const ShortRoleInfo(isAccessible: true, isTeamCrossing: true),
        RoleLevel.admin:
            const ShortRoleInfo(isAccessible: true, isTeamCrossing: true),
      };

  // Return permissions for both teamMultipleUsers and teamWriteTest
  return {
    '11111111-0001-0000-0000-000000000000': {
      // teamMultipleUsers
      RoleDomain.basic: makeDomain(),
      RoleDomain.management: makeDomain(),
    },
    '77777777-0001-0000-0000-000000000000': {
      // teamWriteTest
      RoleDomain.basic: makeDomain(),
      RoleDomain.management: makeDomain(),
    },
  };
}

